<?php
namespace App\Filament\Resources;
use App\Filament\Resources\AppNotificationResource\Pages; use App\Models\AppNotification;
use Filament\Actions\DeleteAction; use Filament\Actions\EditAction; use Filament\Forms\Components\Textarea; use Filament\Forms\Components\TextInput; use Filament\Resources\Resource; use Filament\Schemas\Schema; use Filament\Tables\Columns\TextColumn; use Filament\Tables\Table;
class AppNotificationResource extends Resource { protected static ?string $model = AppNotification::class; protected static ?string $navigationLabel = 'الإشعارات'; public static function form(Schema $schema): Schema { return $schema->components([TextInput::make('title')->label('العنوان')->required(), Textarea::make('body')->label('النص')->required()]); } public static function table(Table $table): Table { return $table->columns([TextColumn::make('title')->label('العنوان'), TextColumn::make('body')->label('النص')->limit(50), TextColumn::make('created_at')->dateTime()->label('التاريخ')])->recordActions([EditAction::make(), DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListAppNotifications::route('/'), 'create'=>Pages\CreateAppNotification::route('/create'), 'edit'=>Pages\EditAppNotification::route('/{record}/edit')]; } }
